QueryScript.Source:
                      import sailpoint.object.Filter;

                      Filter leaverDateFilter=Filter.notnull("leaverDate");                    
                      queryOptions.addFilter(leaverDateFilter);

                      return queryOptions;

RenderScript.Source:
                    import sailpoint.object.Identity;

                    Identity identity = context.getObjectById(Identity.class, value);

                    if(null!=identity){
                    
                    List entExceptions = identity.getExceptions();
                    if (entExceptions != null && !entExceptions.isEmpty()) {
                    return "false";
                    }else{
                    return "true";
                    }
                    }
                    }

                    import sailpoint.object.Identity;
                    import java.text.SimpleDateFormat;
                    import java.util.Date;
                    import java.util.HashMap;

                    String strCurrentDate=null;
                    Date currentDate=null;
                    Date terminationDate=null;
                    Date termDate = null;
                    SimpleDateFormat sdf = null;

                    long dayDifference=0;    
                    long days=0;
                    int count=0;

                    Identity identity = context.getObjectById(Identity.class, value);

                    if(null!=identity){
                    String leaverDt=identity.getAttribute("leaverDate");
                    sdf = new SimpleDateFormat("yyyyMMdd");
                    strCurrentDate = sdf.format(new Date());
                    currentDate = sdf.parse(strCurrentDate);
                    if(leaverDt != null){

                    termDate = sdf.parse(leaverDt);            
                    }                    
                    if(termDate!=null){

                    dayDifference=currentDate.getTime()-termDate.getTime();
                    days=dayDifference / 1000 / 60 / 60 / 24;
                    
                    } 

                    return days;
                    }
